// Validate webhook secret
const secret = $input.first().json.headers?.['x-webhook-secret'];
if (!secret || secret !== $env.WEBHOOK_SECRET) {
  throw new Error('Unauthorized: invalid or missing x-webhook-secret header');
}

// Parse body
const body = $input.first().json.body || $input.first().json;
const { user_id, difficulty_override } = body;

if (!user_id) {
  throw new Error('Invalid request: user_id is required');
}

return [{
  json: {
    user_id,
    difficulty_override: difficulty_override || null
  }
}];

// Analyze the last 30 corrections to find top error categories
const corrections = $input.all().map(item => item.json);
const userId = $('Validate Request').first().json.user_id;
const difficultyOverride = $('Validate Request').first().json.difficulty_override;

if (corrections.length === 0) {
  // No history — generate beginner exercises
  return [{
    json: {
      user_id: userId,
      topErrors: ['article gender (der/die/das)', 'verb conjugation (ich/du/er forms)', 'basic sentence word order'],
      cefrLevel: difficultyOverride || 'A1',
      hasHistory: false
    }
  }];
}

// Known German grammar error categories to scan for
const errorKeywords = {
  'article gender': ['der', 'die', 'das', 'article', 'gender', 'nominative', 'accusative', 'dative', 'genitive', 'ein', 'eine'],
  'verb conjugation': ['conjugat', 'verb', 'sein', 'haben', 'modal', 'irregular', 'present tense', 'past tense', 'ich/du/er'],
  'word order': ['word order', 'verb-second', 'inversion', 'main clause', 'subordinate', 'V2'],
  'adjective endings': ['adjective', 'adjektiv', 'ending', '-en', '-em', '-er', '-es'],
  'separable verbs': ['separable', 'prefix', 'trennbar', 'anrufen', 'aufmachen'],
  'prepositions': ['preposition', 'preposition + case', 'an', 'auf', 'bei', 'in', 'mit', 'nach', 'von', 'zu', 'durch'],
  'umlauts / spelling': ['umlaut', 'ß', 'spelling', 'schreibung', 'capitalization'],
  'modal verbs': ['modal', 'können', 'müssen', 'dürfen', 'sollen', 'wollen', 'mögen'],
  'past tense (Perfekt)': ['perfekt', 'haben + participle', 'sein + participle', 'past participle', 'ge-'],
  'subordinating conjunctions': ['weil', 'dass', 'obwohl', 'subordinat', 'conjunction', 'nebensatz']
};

// Count keyword matches in explanations
const errorCounts = {};
for (const [category, keywords] of Object.entries(errorKeywords)) {
  errorCounts[category] = 0;
  for (const correction of corrections) {
    const explanation = (correction.explanation || '').toLowerCase();
    if (keywords.some(kw => explanation.includes(kw.toLowerCase()))) {
      errorCounts[category]++;
    }
  }
}

// Sort by frequency, take top 3
const sorted = Object.entries(errorCounts)
  .sort((a, b) => b[1] - a[1])
  .filter(([, count]) => count > 0)
  .slice(0, 3)
  .map(([category]) => category);

// If fewer than 3 categories found, add defaults
const defaults = ['article gender', 'verb conjugation', 'word order'];
while (sorted.length < 3) {
  const fallback = defaults.find(d => !sorted.includes(d));
  if (fallback) sorted.push(fallback);
  else break;
}

// Determine CEFR level from recent corrections
const cefrLevels = corrections.map(c => c.cefr_estimate).filter(Boolean);
const cefrOrder = ['A1', 'A2', 'B1', 'B2', 'C1', 'C2'];
let cefrLevel = 'A2';
if (cefrLevels.length > 0) {
  // Use the median CEFR level
  const sorted_cefr = cefrLevels
    .filter(l => cefrOrder.includes(l))
    .sort((a, b) => cefrOrder.indexOf(a) - cefrOrder.indexOf(b));
  cefrLevel = sorted_cefr[Math.floor(sorted_cefr.length / 2)] || 'A2';
}

return [{
  json: {
    user_id: userId,
    topErrors: sorted,
    cefrLevel: difficultyOverride || cefrLevel,
    hasHistory: true,
    totalCorrectionsAnalyzed: corrections.length
  }
}];

// Parse GPT exercise response and build final payload
const gptData = $('GPT Generate Exercises').first().json;
const analyzeData = $('Analyze Error Patterns').first().json;

const rawContent = gptData?.choices?.[0]?.message?.content || '{}';

let exerciseSet;
try {
  const cleaned = rawContent.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  exerciseSet = JSON.parse(cleaned);
} catch (e) {
  // Fallback if GPT fails to return valid JSON
  exerciseSet = {
    exercises: [
      {
        id: 1,
        type: 'fill-in-the-blank',
        target_error: analyzeData.topErrors[0] || 'article gender',
        instruction: 'Fill in the correct article (der/die/das/ein/eine).',
        prompt: '___ Buch liegt auf dem Tisch.',
        hint: 'Buch is a neuter noun.',
        expected_answer: 'Das Buch liegt auf dem Tisch.',
        explanation: '"Buch" (book) is neuter, so the definite article is "das".',
        alternative_answers: ['Ein Buch liegt auf dem Tisch.']
      }
    ],
    cefr_level: analyzeData.cefrLevel,
    focus_areas: analyzeData.topErrors
  };
}

return [{
  json: {
    success: true,
    user_id: analyzeData.user_id,
    generated_at: new Date().toISOString(),
    has_history: analyzeData.hasHistory,
    corrections_analyzed: analyzeData.totalCorrectionsAnalyzed || 0,
    exercise_set: exerciseSet
  }
}];
